function loadImage(key,src){return new Promise((resolve)=>{const img=new Image();img.onload=()=>{assets[key]=img;resolve();};img.src=src;});}
function loadFrameSequence(key,srcs){return Promise.all(srcs.map((src)=>new Promise((resolve)=>{const img=new Image();img.onload=()=>resolve(img);img.src=src;}))).then((frames)=>{assets[key]=frames;});}
function clamp(v,min,max){return Math.max(min,Math.min(max,v));}
function mixPalette(level,from,to){return[from[0]+Math.round((to[0]-from[0])*level),from[1]+Math.round((to[1]-from[1])*level),from[2]+Math.round((to[2]-from[2])*level)];}
function currentZone(){return zones.find((zone)=>hero.x>=zone.x&&hero.x<zone.x+zone.width)||zones[zones.length-1];}
function applyProfileToStageHero(){if(!progressApi||!currentStageProfile){return;}const derived=progressApi.deriveHeroStats(currentStageProfile),combat=progressApi.deriveHeroCombat(currentStageProfile);hero.maxLife=derived.maxLife;hero.maxEnergy=derived.maxEnergy;hero.life=hero.maxLife;hero.energy=hero.maxEnergy;heroEnergyRegenPerSecond=derived.energyRegen??18;HERO_ACTION_RULES.attack.damage=combat.attackDamage;HERO_ACTION_RULES.special.damage=combat.specialDamage;HERO_ACTION_RULES.dash.damage=combat.dashDamage;}
function applyProfileEnemyScaling(){if(!progressApi||!currentStageProfile){return;}const scaling=progressApi.getEnemyScaling(currentStageProfile);for(const mob of mobs){const lifeRatio=mob.maxLife>0?mob.life/mob.maxLife:1;mob.maxLife=Math.max(1,Math.round(mob.maxLife*scaling.mobMultiplier));mob.life=Math.max(1,Math.round(mob.maxLife*lifeRatio));mob.damage=Math.max(1,Math.round(mob.damage*scaling.mobDamageMultiplier));}boss.maxLife=Math.max(1,Math.round(boss.maxLife*scaling.bossMultiplier));boss.life=boss.maxLife;}
async function bootstrapStageProfile(){progressApi=await import("./gameProgress.js");currentStageUser=await progressApi.requireAuthenticatedUser("./login.html");try{currentStageProfile=await progressApi.getUserProfile(currentStageUser.uid,currentStageUser);}catch(error){console.warn("Falling back to a local stage profile because Firestore could not be loaded:",error);currentStageProfile=progressApi.normalizeProfile({},currentStageUser);}applyProfileToStageHero();}
