function getHeroActionFrameNumber(actionName,timeSeconds){const animation=heroAnimations[actionName];if(!animation){return 0;}return Math.min(Math.floor(timeSeconds*animation.fps),animation.frameOrder.length-1);}
function getHallokinTransformValue(values,frameNumber,fallback){return Array.isArray(values)?(values[Math.min(frameNumber,values.length-1)]??fallback):fallback;}
