function getHallokinDarkSpellConfig(actionName){return HALL0KIN_DARK_SPELLS[actionName]??null;}
function getHallokinDarkSpellCastDuration(actionName){const spellConfig=getHallokinDarkSpellConfig(actionName),animation=heroAnimations[actionName];if(!animation||!spellConfig){return animation?(animation.frameOrder.length/animation.fps):0;}const holdFrame=Math.min(spellConfig.castHoldFrame,animation.frameOrder.length-1);return(holdFrame+1)/animation.fps;}
