function drawSheetAnimation(animation,x,y,facing,timeSeconds){const image=assets[animation.key];const frameIndex=getAnimationFrame(animation,timeSeconds);const trim=animation.trim;let sourceX=frameIndex*animation.frameWidth,sourceY=0,sourceWidth=animation.frameWidth,sourceHeight=animation.frameHeight,drawWidth=animation.frameWidth*animation.scale,drawHeight=animation.frameHeight*animation.scale,drawY=animation.anchorY!=null?y-(animation.anchorY*animation.scale):y-drawHeight;if(trim){sourceX+=trim.x;sourceY=trim.y;sourceWidth=trim.width;sourceHeight=trim.height;drawWidth=trim.width*animation.scale;drawHeight=trim.height*animation.scale;drawY=animation.anchorY!=null?y-(animation.anchorY*animation.scale):y-drawHeight+(animation.groundOffset??0);}const frameImage=animation.effect==="hallokinShadowHero"?createHallokinShadowFrame(image,sourceX,sourceY,sourceWidth,sourceHeight):image;const anchorX=(animation.anchorX??((trim?.width??animation.frameWidth)*0.5))*animation.scale;ctx.save();ctx.translate(Math.round(x-camera.x),Math.round(drawY));ctx.scale(facing,1);ctx.drawImage(frameImage,animation.effect==="hallokinShadowHero"?0:sourceX,animation.effect==="hallokinShadowHero"?0:sourceY,sourceWidth,sourceHeight,Math.round(facing===1?-anchorX:-(drawWidth-anchorX)),0,Math.round(drawWidth),Math.round(drawHeight));ctx.restore();}
