function updateHero(dt){heroCooldowns.attack=Math.max(0,heroCooldowns.attack-dt);heroCooldowns.special=Math.max(0,heroCooldowns.special-dt);heroCooldowns.dash=Math.max(0,heroCooldowns.dash-dt);hero.hurtTimer=Math.max(0,hero.hurtTimer-dt);hero.invulnerableTimer=Math.max(0,hero.invulnerableTimer-dt);hero.energy=Math.min(hero.maxEnergy,hero.energy+(heroEnergyRegenPerSecond*dt));if(hero.action){hero.action.time+=dt;const rule=HERO_ACTION_RULES[hero.action.name];if(!hero.action.hitApplied&&hero.action.time>=hero.action.hitTime){applyHeroAttackHit(rule);hero.action.hitApplied=true;}if(hero.action.time>=hero.action.duration){hero.action=null;}}const input=(controls.right?1:0)-(controls.left?1:0);const targetSpeed=hero.action?0:(input*hero.speed);const accel=hero.onGround?2400:1700;const friction=hero.onGround?2200:900;if(input!==0&&!hero.action){hero.facing=input;if(hero.vx<targetSpeed){hero.vx=Math.min(targetSpeed,hero.vx+(accel*dt));}else if(hero.vx>targetSpeed){hero.vx=Math.max(targetSpeed,hero.vx-(accel*dt));}}else if(hero.vx!==0){const amount=Math.min(Math.abs(hero.vx),(hero.action?accel:friction)*dt);hero.vx-=Math.sign(hero.vx)*amount;}if(jumpQueued&&hero.onGround&&!hero.action){hero.vy=-hero.jumpSpeed;hero.onGround=false;}jumpQueued=false;hero.vy+=WORLD.gravity*dt;hero.vy=Math.min(hero.vy,1200);const previousY=hero.y;hero.x+=hero.vx*dt;hero.y+=hero.vy*dt;resolveLanding(hero,previousY);hero.x=clamp(hero.x,0,WORLD.width-hero.width);for(const hazard of hazards){if(hero.x+hero.width>hazard.x&&hero.x<hazard.x+hazard.width&&hero.y+hero.height>hazard.y+12){resetHero();return;}}if(hero.y>WORLD.height+120){resetHero();return;}if(hero.action){hero.animation=hero.action.name;}else if(!hero.onGround){hero.animation=hero.vy<0?"jump":"fall";}else if(Math.abs(hero.vx)>24){hero.animation="run";}else{hero.animation="idle";}}
function updateMobs(dt){for(const mob of mobs){if(mob.removing){continue;}mob.hitFlash=Math.max(0,mob.hitFlash-dt);if(mob.dead){mob.deathTime+=dt;if(mob.deathTime>=mob.deathDuration){mob.removing=true;}continue;}mob.attackTimer=Math.max(0,mob.attackTimer-dt);const dxToHero=hero.x-mob.x;const dyToHero=Math.abs((hero.y+hero.height)-(mob.y+mob.height));const heroInAggro=Math.abs(dxToHero)<=mob.aggroRange&&dyToHero<120;const heroInAttack=Math.abs(dxToHero)<=mob.attackRange&&dyToHero<100;if(mob.animation==="hurt"){mob.hurtTime+=dt;if(mob.hurtTime>=mob.hurtDuration){mob.animation="walk";}}else if(mob.animation==="attack"){mob.attackTime+=dt;const attackAnimation=mobTemplates[mob.type].attack;const frameIndex=Math.min(Math.floor(mob.attackTime*attackAnimation.fps),getAnimationFrameCount(attackAnimation)-1);if(!mob.hitApplied&&frameIndex>=attackAnimation.hitFrame){mob.hitApplied=true;if(heroInAttack){handleHeroDamage(mob.damage,dxToHero>0?1:-1);}}if(mob.attackTime>=mob.attackDuration){mob.animation="walk";}}else{if(heroInAttack&&mob.attackTimer<=0){mob.animation="attack";mob.attackTime=0;mob.hitApplied=false;mob.attackTimer=mob.attackCooldown;mob.vx=0;}else if(heroInAggro){mob.direction=dxToHero>=0?1:-1;mob.vx=mob.direction*mob.speed*2;}else{mob.vx=mob.direction*mob.speed;}}mob.vy+=WORLD.gravity*dt;mob.vy=Math.min(mob.vy,1100);const previousY=mob.y;mob.x+=mob.vx*dt;mob.y+=mob.vy*dt;if(mob.x<=mob.minX){mob.x=mob.minX;mob.direction=1;}else if(mob.x>=mob.maxX){mob.x=mob.maxX;mob.direction=-1;}resolveLanding(mob,previousY);}mobs=mobs.filter((mob)=>!mob.removing);}
